--
-- Name: bulk_update_verification(integer[], boolean, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text DEFAULT 'admin'::text) RETURNS TABLE(office_id bigint, updated boolean, error_message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  office_id_val integer;
BEGIN
  FOREACH office_id_val IN ARRAY office_ids
  LOOP
    BEGIN
      UPDATE public.iebc_offices
      SET
        verified = verified_status,
        verified_at = CASE WHEN verified_status THEN NOW() ELSE NULL END,
        verified_by = CASE WHEN verified_status THEN verified_by_user ELSE NULL END,
        updated_at = NOW()
      WHERE id = office_id_val;

      RETURN QUERY
      SELECT office_id_val::bigint, true, NULL::text;

    EXCEPTION WHEN OTHERS THEN
      RETURN QUERY
      SELECT office_id_val::bigint, false, SQLERRM::text;
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION public.bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text) OWNER TO postgres;

