--
-- Name: get_office_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_office_stats() RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    total_offices INTEGER;
    verified_offices INTEGER;
    total_contributions INTEGER;
    pending_contributions INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_offices FROM public.iebc_offices;
    SELECT COUNT(*) INTO verified_offices FROM public.iebc_offices WHERE verified = true;
    SELECT COUNT(*) INTO total_contributions FROM public.iebc_office_contributions;
    SELECT COUNT(*) INTO pending_contributions FROM public.iebc_office_contributions WHERE status = 'pending';
    
    RETURN jsonb_build_object(
        'total_offices', total_offices,
        'verified_offices', verified_offices,
        'verification_rate', CASE WHEN total_offices > 0 THEN ROUND((verified_offices::NUMERIC / total_offices::NUMERIC) * 100, 1) ELSE 0 END,
        'total_contributions', total_contributions,
        'pending_contributions', pending_contributions
    );
END;
$$;


ALTER FUNCTION public.get_office_stats() OWNER TO postgres;

--
-- Name: get_office_stats(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_office_stats(office_id_param integer) RETURNS TABLE(office_id integer, confirmation_count bigint, avg_confirmation_weight numeric, last_confirmed_at timestamp with time zone, recent_confirmations bigint, status_reports_count bigint, contact_updates_count bigint, contributions_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    o.id AS office_id,
    COUNT(DISTINCT c.id) AS confirmation_count,
    AVG(c.confirmation_weight) AS avg_confirmation_weight,
    MAX(c.confirmed_at) AS last_confirmed_at,
    COUNT(DISTINCT CASE WHEN c.confirmed_at > NOW() - INTERVAL '30 days' THEN c.id END) AS recent_confirmations,
    COUNT(DISTINCT os.id) AS status_reports_count,
    COUNT(DISTINCT cu.id) AS contact_updates_count,
    COUNT(DISTINCT cont.id) AS contributions_count
  FROM public.iebc_offices o
  LEFT JOIN public.iebc_office_contributions cont ON o.id = cont.original_office_id
  LEFT JOIN public.confirmations c ON cont.id = c.contribution_id
  LEFT JOIN public.operational_status_history os ON o.id = os.office_id
  LEFT JOIN public.contact_update_requests cu ON o.id = cu.office_id
  WHERE o.id = office_id_param
  GROUP BY o.id;
END;
$$;


ALTER FUNCTION public.get_office_stats(office_id_param integer) OWNER TO postgres;

