--
-- Name: get_offices_by_status(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_offices_by_status(status_filter text, limit_count integer DEFAULT 100) RETURNS TABLE(office_id bigint, county text, constituency_name text, current_status text, reason text, reported_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT DISTINCT ON (o.id)
    o.id AS office_id,
    o.county,
    o.constituency_name,
    os.status AS current_status,
    os.notes AS reason,
    os.created_at AS reported_at
  FROM public.iebc_offices o
  JOIN public.operational_status_history os
    ON o.id = os.office_id
  WHERE os.status = status_filter
    AND o.verified = true
  ORDER BY o.id, os.created_at DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION public.get_offices_by_status(status_filter text, limit_count integer) OWNER TO postgres;

