--
-- Name: normalize_county_name(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.normalize_county_name(name text) RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $_$
BEGIN
    RETURN LOWER(
        REGEXP_REPLACE(
            REGEXP_REPLACE(
                REGEXP_REPLACE(
                    REGEXP_REPLACE(
                        REGEXP_REPLACE($1, 
                        '\s*CITY\s*', '', 'i'), -- Remove 'CITY'
                    '[-''()]', ' ', 'g'),      -- Replace special chars with space
                '[^a-z0-9\s]', '', 'g'),       -- Remove remaining non-alphanumeric
            '\s+', ' ', 'g'),                 -- Collapse multiple spaces
        ' ', '', 'g')                         -- Remove all spaces
    );
END;
$_$;


ALTER FUNCTION public.normalize_county_name(name text) OWNER TO postgres;

--
-- Name: normalize_text(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.normalize_text(text_to_normalize text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
    -- Convert to lowercase, remove all non-alphanumeric characters, and trim whitespace
    RETURN regexp_replace(lower(trim(text_to_normalize)), '[^a-z0-9]', '', 'g');
END;
$$;


