--
-- Name: promote_contribution_to_office(bigint, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.promote_contribution_to_office(p_contribution_id bigint, p_admin_id text, p_office_data jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_contribution_record record;
    v_existing_office_id bigint;
    v_constituency_name text;
    v_constituency_id integer;
    v_office_id bigint;
    v_action_taken text;
    v_exact_constituency_name text;
    v_debug_info jsonb;
BEGIN
    -- Get the contribution data
    SELECT * INTO v_contribution_record 
    FROM iebc_office_contributions 
    WHERE id = p_contribution_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'Contribution not found');
    END IF;
    
    -- Initialize debug info
    v_debug_info := jsonb_build_object(
        'original_constituency', v_contribution_record.submitted_constituency,
        'original_constituency_code', v_contribution_record.submitted_constituency_code
    );
    
    -- Handle constituency
    v_constituency_name := v_contribution_record.submitted_constituency;
    v_constituency_id := v_contribution_record.submitted_constituency_code;
    
    -- If constituency_code is null, try to find by name
    IF v_constituency_id IS NULL THEN
        SELECT id, name INTO v_constituency_id, v_exact_constituency_name
        FROM constituencies 
        WHERE LOWER(TRIM(name)) = LOWER(TRIM(v_constituency_name))
        LIMIT 1;
        
        IF v_constituency_id IS NOT NULL THEN
            v_constituency_name := v_exact_constituency_name;
            v_debug_info := v_debug_info || jsonb_build_object('found_by_name', true, 'found_id', v_constituency_id);
        ELSE
            -- Try fuzzy matching if exact match fails
            SELECT id, name INTO v_constituency_id, v_exact_constituency_name
            FROM constituencies 
            WHERE LOWER(name) LIKE LOWER('%' || v_constituency_name || '%')
            LIMIT 1;
            
            IF v_constituency_id IS NOT NULL THEN
                v_constituency_name := v_exact_constituency_name;
                v_debug_info := v_debug_info || jsonb_build_object('found_by_fuzzy', true, 'found_id', v_constituency_id);
            ELSE
                -- Last resort: use a known valid constituency
                SELECT id, name INTO v_constituency_id, v_constituency_name
                FROM constituencies 
                WHERE name = 'EMBAKASI WEST'
                LIMIT 1;
                
                IF v_constituency_id IS NULL THEN
                    -- Ultimate fallback
                    SELECT id, name INTO v_constituency_id, v_constituency_name
                    FROM constituencies 
                    LIMIT 1;
                END IF;
                
                v_debug_info := v_debug_info || jsonb_build_object('used_fallback', true, 'fallback_id', v_constituency_id);
            END IF;
        END IF;
    ELSE
        -- Check if constituency ID exists
        IF EXISTS(SELECT 1 FROM constituencies WHERE id = v_constituency_id) THEN
            SELECT name INTO v_exact_constituency_name 
            FROM constituencies 
            WHERE id = v_constituency_id;
            
            IF v_exact_constituency_name IS NOT NULL THEN
                v_constituency_name := v_exact_constituency_name;
            END IF;
        ELSE
            -- Invalid ID, find by name
            SELECT id, name INTO v_constituency_id, v_exact_constituency_name
            FROM constituencies 
            WHERE LOWER(TRIM(name)) = LOWER(TRIM(v_constituency_name))
            LIMIT 1;
            
            IF v_constituency_id IS NULL THEN
                -- Try fuzzy matching
                SELECT id, name INTO v_constituency_id, v_exact_constituency_name
                FROM constituencies 
                WHERE LOWER(name) LIKE LOWER('%' || v_constituency_name || '%')
                LIMIT 1;
            END IF;
        END IF;
    END IF;
    
    -- Final safety check
    IF v_constituency_id IS NULL OR NOT EXISTS(SELECT 1 FROM constituencies WHERE id = v_constituency_id) THEN
        RETURN jsonb_build_object(
            'error', 'No valid constituency found',
            'debug', v_debug_info,
            'contribution_constituency', v_contribution_record.submitted_constituency,
            'final_constituency_id', v_constituency_id
        );
    END IF;
    
    -- SIMPLE EXACT MATCHING
    SELECT id INTO v_existing_office_id 
    FROM iebc_offices 
    WHERE constituency_code = v_constituency_id 
    AND office_location = v_contribution_record.submitted_office_location;
    
    IF v_existing_office_id IS NOT NULL THEN
        -- UPDATE existing office
        UPDATE iebc_offices SET
            county = v_contribution_record.submitted_county,
            constituency = v_constituency_name,
            constituency_code = v_constituency_id,
            office_location = v_contribution_record.submitted_office_location,
            landmark = v_contribution_record.submitted_landmark,
            latitude = v_contribution_record.submitted_latitude,
            longitude = v_contribution_record.submitted_longitude,
            verified = true,
            verified_at = NOW(),
            verifier_id = p_admin_id,
            verification_source = 'admin_dashboard',
            updated_at = NOW(),
            image_url = COALESCE(v_contribution_record.image_public_url, image_url),
            created_from_contribution_id = p_contribution_id
        WHERE id = v_existing_office_id
        RETURNING id INTO v_office_id;
        
        v_action_taken := 'updated';
    ELSE
        -- INSERT new office
        INSERT INTO iebc_offices (
            county, constituency, constituency_code, office_location, landmark,
            latitude, longitude, verified, verified_at, verifier_id, 
            verification_source, image_url, created_from_contribution_id
        ) VALUES (
            v_contribution_record.submitted_county,
            v_constituency_name,
            v_constituency_id,
            v_contribution_record.submitted_office_location,
            v_contribution_record.submitted_landmark,
            v_contribution_record.submitted_latitude,
            v_contribution_record.submitted_longitude,
            true,
            NOW(),
            p_admin_id,
            'admin_dashboard',
            v_contribution_record.image_public_url,
            p_contribution_id
        ) RETURNING id INTO v_office_id;
        
        v_action_taken := 'created';
    END IF;
    
    -- Update contribution status
    UPDATE iebc_office_contributions 
    SET status = 'verified',
        reviewer_id = p_admin_id,
        reviewed_at = NOW()
    WHERE id = p_contribution_id;
    
    -- Log the action
    INSERT INTO verification_log (
        contribution_id,
        action,
        actor,
        details
    ) VALUES (
        p_contribution_id,
        'verified',
        p_admin_id,
        jsonb_build_object(
            'office_id', v_office_id,
            'action_taken', v_action_taken,
            'constituency_used', v_constituency_name,
            'constituency_id', v_constituency_id,
            'debug_info', v_debug_info
        )
    );
    
    RETURN jsonb_build_object(
        'action', v_action_taken,
        'office_id', v_office_id,
        'contribution_id', p_contribution_id,
        'constituency_used', v_constituency_name,
        'debug', v_debug_info
    );
    
EXCEPTION
    WHEN OTHERS THEN
        INSERT INTO verification_log (
            contribution_id,
            action,
            actor,
            details
        ) VALUES (
            p_contribution_id,
            'failed',
            p_admin_id,
            jsonb_build_object(
                'error', SQLERRM,
                'constituency', v_constituency_name,
                'constituency_id', v_constituency_id,
                'debug_info', v_debug_info
            )
        );
        
        RETURN jsonb_build_object(
            'error', SQLERRM,
            'details', 'Failed to process contribution: ' || SQLERRM,
            'debug', v_debug_info
        );
END;
$$;


