--
-- Name: update_office_constituency_codes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_office_constituency_codes() RETURNS TABLE(updated_count integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  update_count integer := 0;
BEGIN
  WITH updated_offices AS (
    UPDATE iebc_offices io
    SET constituency_code = c.id
    FROM constituencies c
    WHERE 
      io.constituency_name IS NOT NULL 
      AND io.county IS NOT NULL
      AND c.name ILIKE '%' || io.constituency_name || '%'
      AND c.county_name ILIKE '%' || io.county || '%'
      AND io.constituency_code IS DISTINCT FROM c.id
    RETURNING 1
  )
  SELECT COUNT(*) INTO update_count FROM updated_offices;
  
  RETURN QUERY SELECT update_count;
END;
$$;


