--
-- Name: validate_constituency_exists(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_constituency_exists(constituency_name text, county_name text) RETURNS integer
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  constituency_id INTEGER;
BEGIN
  SELECT id INTO constituency_id 
  FROM constituencies 
  WHERE name = constituency_name;
  
  IF constituency_id IS NULL THEN
    -- Try to create the constituency if it doesn't exist
    INSERT INTO constituencies (name, county_id, registration_target)
    VALUES (
      constituency_name,
      (SELECT id FROM counties WHERE name = county_name LIMIT 1),
      0
    )
    RETURNING id INTO constituency_id;
  END IF;
  
  RETURN constituency_id;
END;
$$;


