    formatted_address,
    landmark,
    landmark_type,
    landmark_subtype,
    direction_landmark,
    direction_type,
    direction_distance,
    distance_from_landmark,
    accuracy_meters,
    verification_source,
    verified,
    verified_at,
    verified_latitude,
    verified_longitude,
    verifier_id,
    notes,
    importance_score,
    geocode_method,
    geocode_status,
    geocode_confidence,
    geocode_query,
    successful_geocode_query,
    geocode_queries,
    total_queries_tried,
    result_type,
    source,
    contributor_image_url,
    geom,
    created_at,
    updated_at
   FROM public.iebc_offices
  WHERE ((verified = true) OR (auth.uid() IN ( SELECT core_team.user_id
           FROM public.core_team
          WHERE (core_team.is_admin = true))));


ALTER VIEW public.vw_offices OWNER TO postgres;

