--

COMMENT ON VIEW public.vw_offices IS 'Secure view of IEBC offices with RLS enforcement via security barrier';


--
-- Name: vw_verification_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_verification_status WITH (security_barrier='true', security_invoker='true') AS
 SELECT v.id,
    v.contribution_id,
    v.office_id,
    v.action,
    v.actor,
    v.details,
    v.created_at,
    c.submitted_office_location AS contribution_location,
    c.status AS contribution_status,
    o.office_location,
    o.verified AS office_verified
   FROM ((public.verification_log v
     LEFT JOIN public.iebc_office_contributions c ON ((v.contribution_id = c.id)))
     LEFT JOIN public.iebc_offices o ON ((v.office_id = o.id)))
  WHERE ((auth.uid() IS NOT NULL) OR (auth.uid() IN ( SELECT core_team.user_id
           FROM public.core_team
          WHERE (core_team.is_admin = true))));


ALTER VIEW public.vw_verification_status OWNER TO postgres;

