--
-- Name: iebc_offices Admin Full Access; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin Full Access" ON public.iebc_offices USING ((((auth.jwt() ->> 'role'::text) = 'service_role'::text) OR ( SELECT public.is_admin(auth.uid()) AS is_admin)));


--
-- Name: iebc_office_contributions Admin Full Contributions; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin Full Contributions" ON public.iebc_office_contributions USING (( SELECT public.is_admin(auth.uid()) AS is_admin));


--
-- Name: confirmations Admin Read Confirmations; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin Read Confirmations" ON public.confirmations FOR SELECT USING (( SELECT public.is_admin(auth.uid()) AS is_admin));


--
-- Name: signature_access_log Admin can view access logs; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admin can view access logs" ON public.signature_access_log FOR SELECT USING ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))));


--
-- Name: evidence_documents Admins can delete evidence; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admins can delete evidence" ON public.evidence_documents FOR DELETE TO authenticated USING ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))));


--
-- Name: iebc_office_contributions Admins can do all operations on contributions; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admins can do all operations on contributions" ON public.iebc_office_contributions TO authenticated USING (((auth.jwt() ->> 'email'::text) = ANY (ARRAY['admin@example.com'::text, 'your-email@example.com'::text])));


--
-- Name: constituencies Admins can modify constituencies; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admins can modify constituencies" ON public.constituencies TO authenticated USING ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true)))) WITH CHECK ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))));


--
-- Name: counties Admins can modify counties; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Admins can modify counties" ON public.counties TO authenticated USING ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true)))) WITH CHECK ((auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))));


