--

CREATE POLICY "Audit trail access" ON public.audit_trail FOR SELECT USING (((( SELECT auth.uid() AS uid) IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))) OR (( SELECT auth.uid() AS uid) = user_id)));


--
-- Name: audit_trail Audit trail admin only; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Audit trail admin only" ON public.audit_trail USING ((( SELECT auth.uid() AS uid) IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true)))) WITH CHECK ((( SELECT auth.uid() AS uid) IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true))));


