--
-- Name: evidence_documents Petition creators can view evidence; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Petition creators can view evidence" ON public.evidence_documents FOR SELECT TO authenticated USING (((petition_id IN ( SELECT petitions.id
   FROM public.petitions
  WHERE (petitions.created_by = auth.uid()))) OR (uploaded_by = auth.uid()) OR (auth.uid() IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true)))));


