   FROM public.core_team
  WHERE (core_team.is_admin = true))))) WITH CHECK (((( SELECT auth.uid() AS uid) = created_by) OR (( SELECT auth.uid() AS uid) IN ( SELECT core_team.user_id
   FROM public.core_team
  WHERE (core_team.is_admin = true)))));


